from __future__ import annotations

import json
import os
import re
from json import JSONDecodeError
from typing import Any, Dict, List, Optional, Tuple

from langchain_ollama import ChatOllama

from src.rubric_ids import CANONICAL_DIMENSION_ID_SET, normalize_dimension_id
from src.state import AgentState, JudicialOpinion


def _ollama_timeout_s() -> int:
    raw = str(os.getenv("OLLAMA_TIMEOUT_S", "45")).strip()
    try:
        value = int(raw)
    except Exception:
        value = 45
    return value if value > 0 else 45


def _ollama_num_predict() -> int:
    raw = str(os.getenv("OLLAMA_NUM_PREDICT", "256")).strip()
    try:
        value = int(raw)
    except Exception:
        value = 256
    return value if value > 0 else 256


def _get_llm() -> ChatOllama:
    return ChatOllama(
        model=os.getenv("OLLAMA_MODEL", "deepseek-r1:8b"),
        base_url=os.getenv("OLLAMA_BASE_URL", "http://localhost:11434"),
        format="json",
        temperature=0.2,
        num_predict=_ollama_num_predict(),
        client_kwargs={"timeout": _ollama_timeout_s()},
    )


def _normalize_judge(value: object, fallback: str) -> str:
    text = str(value or "").strip().lower()
    mapping = {
        "prosecutor": "Prosecutor",
        "defense": "Defense",
        "defence": "Defense",
        "techlead": "TechLead",
        "tech_lead": "TechLead",
        "tech lead": "TechLead",
    }
    return mapping.get(text, fallback)


def _coerce_score(value: object, default: int = 3) -> int:
    normalized = _normalize_score(value, default=default)
    return max(1, min(5, normalized))


def _coerce_cited_evidence(value: object) -> List[str]:
    if value is None:
        return []
    if isinstance(value, str):
        v = value.strip()
        return [v] if v else []
    if isinstance(value, list):
        out: List[str] = []
        for item in val

